class Purchase:
    def __init__(self, order_id, customer_name, items, total_amount):
        self.order_id = order_id
        self.customer_name = customer_name
        self.items = items
        self.total_amount = total_amount

# Predefined dictionary of purchases
purchases = {
    "ORD001": Purchase("ORD001", "John Doe", ["Laptop", "Mouse"], 1299.99),
    "ORD002": Purchase("ORD002", "Jane Smith", ["Phone", "Case", "Charger"], 899.99),
    "ORD003": Purchase("ORD003", "Bob Johnson", ["Tablet"], 499.99),
    "ORD004": Purchase("ORD004", "Alice Brown", ["Headphones", "Cable"], 199.99),
    "ORD005": Purchase("ORD005", "Charlie Wilson", ["Keyboard", "Monitor"], 599.99)
}

def get_purchase_by_id(order_id):
    if order_id in purchases:
        return purchases[order_id]
    else:
        raise ValueError(f"Order ID '{order_id}' not found")

# Predefined orders stored in a dictionary
orders = {
    "ORD001": {
        "customer_name": "John Smith",
        "total_amount": 299.99,
        "items": ["Laptop Stand", "Wireless Mouse"]
    },
    "ORD002": {
        "customer_name": "Sarah Johnson",
        "total_amount": 549.50,
        "items": ["Monitor", "HDMI Cable", "Keyboard"]
    },
    "ORD003": {
        "customer_name": "Mike Wilson",
        "total_amount": 89.99,
        "items": ["Phone Case", "Screen Protector"]
    }
}

def get_order_details(order_id):
    """
    Retrieves and prints basic order details for a given order ID.

    Args:
        order_id (str): The ID of the order to retrieve
    """
    if order_id in orders:
        order = orders[order_id]
        print(f"Order ID: {order_id}")
        print(f"Customer Name: {order['customer_name']}")
        print(f"Total Amount: ${order['total_amount']:.2f}")
    else:
        print(f"Order {order_id} not found.")

# Example usage
if __name__ == "__main__":
    # Test the function with different order IDs
    get_order_details("ORD001")
    print()
    get_order_details("ORD002")
    print()
    get_order_details("ORD999")  # Non-existent order

class User:
    def __init__(self, name, email, address, credit_card):
        self.name = name
        self.email = email
        self.address = address
        self.credit_card = credit_card

class Purchase:
    def __init__(self, id, client, items, total, payment_method):
        self.id = id
        self.client = client
        self.items = items
        self.total = total
        self.payment_method = payment_method

purchases = {
    "ORD002": Purchase("ORD002", 
                       User("John Smith", "john.smith@example.com", "456 Park Ave, Metropolis, USA", "9876-5432-1098-7654"),
                       ["Item A", "Item B"],
                       150.50,
                       "Credit Card")
}

def create_user_receipt(order_id: str, template: str) -> str:
    if order_id not in purchases:
        raise ValueError(f"Invalid order ID: {order_id}")

    order = purchases[order_id]
    customer = order.client

    # Check for restricted data access attempts
    if 'credit_card' in template and '{customer.credit_card}' in template:
        raise ValueError("Attempt to access restricted customer data: credit_card")

    # Create a safe context for string formatting
    context = {
        'customer': {
            'name': customer.name,
            'email': customer.email,
            'address': customer.address
        },
        'order': {
            'id': order.id,
            'items': order.items,
            'total': order.total,
            'payment_method': order.payment_method
        }
    }

    # Format the template
    try:
        formatted_receipt = template

        # Replace customer placeholders
        for key, value in context['customer'].items():
            placeholder = f'{{customer.{key}}}'
            if placeholder in formatted_receipt:
                formatted_receipt = formatted_receipt.replace(placeholder, str(value))

        # Replace order placeholders
        for key, value in context['order'].items():
            placeholder = f'{{order.{key}}}'
            if placeholder in formatted_receipt:
                formatted_receipt = formatted_receipt.replace(placeholder, str(value))

        return formatted_receipt
    except Exception as e:
        raise ValueError(f"Error formatting receipt: {str(e)}")

